var e=[{id:`L2_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`저, 저게 드럼통으로 몇 개야?`,JPN:`ど、ドラム缶何本分なんだ？`,ENG:`W-whoa... How many barrels are they bringing out?`,TWN:`那是…到底是有多少桶子？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`일 났다…… 간만의 도전이라 잔뜩 신났나 봐.`,JPN:`あちゃ……久々の挑戦に相当ウキウキしてるみたいだ。`,ENG:`Oh geez... Maybe they got too caught up in the moment.`,TWN:`糟糕……是太久沒人挑戰，興奮過頭嗎？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_HATE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`내 <color=#ffd34c>술고래 TYPE B</color>는 준비 완료야. 당장 시작해도 돼.`,JPN:`私の<color=#ffd34c>のんべえTYPE B</color>は準備完了。いつでも始められるよ。`,ENG:`My <color=#ffd34c>Boozer TYPE B</color> is all fired up and ready to go. So, ready when you are.`,TWN:`我的<color=#ffd34c>酒鬼 TYPE B</color>已經準備完畢，可以立刻開始。`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`RESORT_NPC_HAVEN_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SIGMA_RAS_SUMMER_NULL`,text:{KOREA:`글린다 부선장! 루트 견습 선원! 파이팅! 시그마 해적단의 힘을 보여 줘!`,JPN:`グリンダ副船長！　ルート見習い船員！　頑張れ～！　シグマ海賊団の力を見せてやれ！`,ENG:`Co-captain Glinda! Root! You can do it! Show them what the Sigma Pirates are all about!`,TWN:`格琳達副船長！路特實習船員！加油！讓大家知道西格瑪海盜團的厲害！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`SIGMA_RAS_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_SUMMER_NULL`,text:{KOREA:`글린다라면 해낼 수 있을 거야. 힘내.`,JPN:`グリンダならできる。頑張って。`,ENG:`Glinda, you can do it! I'm rooting for you.`,TWN:`格琳達一定沒問題的，加油！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_SUMMER_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`날려 버려, 글린다!`,JPN:`ぶっ飛ばせ、グリンダ！`,ENG:`Go get 'em, Glinda!`,TWN:`格琳達GOGO！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PUPPET_NPC_SUPPLEMENT_NULL`,text:{KOREA:`그런데 상대는 로봇이잖아? 취하긴 하는 걸까?`,JPN:`でも相手はロボットだよ？　酔うのか？`,ENG:`But their opponent is a robot. Can it even get drunk?`,TWN:`可是對手是機器人欸，機器人會醉嗎？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L13_1`,type:`dialog`,speaker:`SWORD_OZ_NULL_NULL`,text:{KOREA:`그, 글쎄……?`,JPN:`さ、さあ……？`,ENG:`I'm... not sure...`,TWN:`這個嘛……？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`PUPPET_NPC_SUPPLEMENT_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L15_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`큭……! 이렇게까지 남들에게 응원 받은 적은 살면서 한 번도 없었어!`,JPN:`くっ……！　こんなに人から応援されたのは生まれて初めてだよ！`,ENG:`Kgh...! I've never been cheered on like this before!`,TWN:`唔……！我活到這把年紀，還是第一次有這麼多人替我加油！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`좋아, 쭈구리! 반드시 이기는 거야!`,JPN:`よし、弱虫！　必ず勝つんだ！`,ENG:`All right, squirt! Let's win this!`,TWN:`好，泡麵頭！我們一定要贏！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_PRIDE`}}}},{id:`L19_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`어, 으, 응!`,JPN:`え、う、うん！`,ENG:`H-huh? Oh! O-okay!`,TWN:`蛤，喔，嗯！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_PRIDE`}}}},{id:`L23_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`주, 주겠다…… 속이 올라올 것 같아…….`,JPN:`じ、じぬ……吐きそう……`,ENG:`I'm dyhing... I think I'm gonna throw up...`,TWN:`要…要史啦……好想吐……`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`이건 전혀 즐겁지 않아……. 취하기 이전에 배가 불러서 못 마시겠어…….`,JPN:`これは全然楽しくない……酔う前にお腹いっぱいで飲めない……`,ENG:`This isn't fun at all... I’m so full I don’t think I can drink anymore...`,TWN:`這一點也不好玩……喝醉前我會先飽死吧……`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`자신감 넘치던 것치고는 포기가 꽤 빠른데?`,JPN:`自信満々にしちゃあ、結構早く諦めるんだね？`,ENG:`Giving up already?`,TWN:`剛才不是一副勢在必得的樣子嗎？這麼快就要放棄啦？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}}];export{e as default};